def default_validate_transaction(event: Dict[str, Any], meta: Dict[str, Any]) -> Dict[str, Any]:
    txn = event.get("transaction") or event.get("txn") or event
    required = ["transaction_id", "amount", "currency", "timestamp"]
    missing = [k for k in required if k not in txn]
    if missing:
        raise ValueError(f"Missing required fields: {missing}")
    return {"status": "validated", "transaction_id": txn.get("transaction_id")}


def default_authorize_transaction(event: Dict[str, Any], meta: Dict[str, Any]) -> Dict[str, Any]:
    txn = event.get("transaction") or event.get("txn") or event
    amount = float(txn.get("amount", 0))
    if amount <= 0:
        raise ValueError("Invalid amount")
    return {"status": "authorized", "transaction_id": txn.get("transaction_id")}


def default_settle_transaction(event: Dict[str, Any], meta: Dict[str, Any]) -> Dict[str, Any]:
    txn = event.get("transaction") or event.get("txn") or event
    return {"status": "settled", "transaction_id": txn.get("transaction_id")}


